const LANG_KEY = "gamepad_lang";
let _langFallback = "en";
function getLang(){
  try { return localStorage.getItem(LANG_KEY) || "en"; }
  catch(e){ return _langFallback; }
}
function setLang(code){
  _langFallback = code;
  try { localStorage.setItem(LANG_KEY, code); }
  catch(e){ /* storage unavailable (private mode, quota, not yet ready) — keep in-memory fallback */ }
}
function t(key,vars){
  try {
    const lang=getLang();
    const dict=TRANSLATIONS[lang]||TRANSLATIONS.en;
    let str=dict[key]??TRANSLATIONS.en[key]??key;
    if(vars)Object.entries(vars).forEach(([k,v])=>{str=str.replace(`{${k}}`,v);});
    return str;
  } catch(e){
    return key;
  }
}
function currentT(){
  try { return TRANSLATIONS[getLang()]||TRANSLATIONS.en; }
  catch(e){ return TRANSLATIONS.en; }
}
const LANGUAGES=["en","sk","es","pt","de","fr","it","ru","tr","ja","ko","zh"];
